import { Fragment, useEffect, useMemo, useRef } from 'react'
import { Badge } from '@/components/ui/badge'
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/components/ui/collapsible'
import { Bot, ChevronRight, Code2, MessageSquare, Timer, User, Zap } from 'lucide-react'
import { formatMs, formatToolValue } from '@/lib/observability-format'
import type { ChatItem, SessionMetrics, TurnRecord } from '@/lib/observability-types'
import { useTranscript } from '@/lib/observability-hooks'

/** Per-metric latency thresholds in ms. Tuned to voice-pipeline SLOs so
 * each pill gives a real signal (not all-green at any sub-second value).
 * `good` upper bound, `warn` upper bound — anything above is `bad`. */
const LATENCY_THRESHOLDS: Record<string, { good: number; warn: number }> = {
  Perceived: { good: 800, warn: 1500 },
  STT: { good: 300, warn: 600 },
  'LLM TTFT': { good: 500, warn: 1200 },
  TTS: { good: 300, warn: 600 },
}

// Per-turn metric pills sit just below an agent or user bubble. Bg-card
// + tinted text/border reads as a quieter row than the filled-bg pills
// the dashboard used to ship. The label is muted so the value is what
// the eye lands on; only "bad" tones lean on font-weight to draw
// attention to a problem turn.
const PILL_BASE =
  'rounded border px-1.5 py-0.5 text-[10px] font-mono font-normal tabular-nums bg-card'

// ── Search-match annotation ──────────────────────────────────────────
// The sessions list filters with Postgres websearch_to_tsquery; opening a
// session from an active search carries the query here so the transcript
// can annotate what (approximately) matched. Postgres does real English
// stemming — this is a deliberate client-side approximation (shared stem
// prefix after stripping common suffixes), good enough to point the eye.
// The list snippet stays the server-truth for what matched.

const STEM_SUFFIXES = ['ations', 'ation', 'ings', 'ing', 'ions', 'ion', 'ed', 'es', 'ly', 's']

const crudeStem = (word: string): string => {
  for (const suffix of STEM_SUFFIXES) {
    if (word.length - suffix.length >= 3 && word.endsWith(suffix)) {
      return word.slice(0, -suffix.length)
    }
  }
  return word
}

/** Words worth highlighting from a websearch-style query: quoted phrases
 * contribute their words; `-excluded` terms and bare or/and are dropped. */
const parseSearchTerms = (q: string | undefined): string[] => {
  if (!q) return []
  return q
    .replace(/"/g, ' ')
    .split(/\s+/)
    .filter((w) => w && !w.startsWith('-'))
    .map((w) => w.replace(/[^\p{L}\p{N}']/gu, '').toLowerCase())
    .filter((w) => w.length >= 2 && w !== 'or' && w !== 'and')
}

/** Stem equality, or a 3+-char stem-prefix relation in either direction —
 * short terms can act as prefix wildcards ("can" lights "cancel"); accepted
 * for an annotation aid. */
const wordMatchesTerm = (word: string, term: string): boolean => {
  const a = crudeStem(word.toLowerCase())
  const b = crudeStem(term)
  if (a === b) return true
  return (b.length >= 3 && a.startsWith(b)) || (a.length >= 3 && b.startsWith(a))
}

/** Capture group keeps word tokens at odd indices of split() so the
 * renderer tests only words and passes punctuation through untouched. */
const WORD_TOKEN = /(\p{L}[\p{L}\p{N}']*)/gu

const textHasMatch = (text: string, terms: string[]): boolean => {
  if (!terms.length) return false
  const words = text.match(WORD_TOKEN)
  return !!words?.some((w) => terms.some((t) => wordMatchesTerm(w, t)))
}

const HighlightedText = ({ text, terms }: { text: string; terms: string[] }) => {
  if (!terms.length) return <>{text}</>
  return (
    <>
      {text.split(WORD_TOKEN).map((tok, i) =>
        i % 2 === 1 && terms.some((t) => wordMatchesTerm(tok, t)) ? (
          <mark key={i} className="rounded-[2px] bg-warning-bg px-0.5 font-medium text-warning-fg">
            {tok}
          </mark>
        ) : (
          <Fragment key={i}>{tok}</Fragment>
        ),
      )}
    </>
  )
}

/** STT confidence pill on user bubbles. Thresholds mirror voice SLOs:
 * ≥ 0.9 green, ≥ 0.7 amber, below red. */
const ConfidencePill = ({ value }: { value: number | undefined }) => {
  if (value == null) return null
  const tone =
    value >= 0.9
      ? 'text-success-fg border-success-border'
      : value >= 0.7
        ? 'text-warning-fg border-warning-border'
        : 'text-destructive border-destructive-border font-semibold'
  const pct = Math.round(value * 100)
  return (
    <Badge
      variant="outline"
      title={`Transcript confidence: ${pct}%`}
      aria-label={`Transcript confidence: ${pct}%`}
      className={`${PILL_BASE} ${tone}`}
    >
      <span className="text-muted-foreground">CONF</span>
      &nbsp;&nbsp;{pct}%
    </Badge>
  )
}

const LatencyPill = ({ label, ms }: { label: string; ms: number | undefined }) => {
  if (ms == null) return null
  const th = LATENCY_THRESHOLDS[label] ?? { good: 500, warn: 1500 }
  const tone =
    ms <= th.good
      ? 'text-success-fg border-success-border'
      : ms <= th.warn
        ? 'text-warning-fg border-warning-border'
        : 'text-destructive border-destructive-border font-semibold'
  return (
    <Badge
      variant="outline"
      title={`${label}: ${formatMs(ms)}`}
      className={`${PILL_BASE} ${tone}`}
    >
      <span className="text-muted-foreground">{label}</span>
      &nbsp;&nbsp;{formatMs(ms)}
    </Badge>
  )
}

/** Silence marker between turns — rendered when the gap between the previous
 * turn's agent speech end and this turn's user speech start crosses the
 * dead-air threshold reported in the metrics summary. */
const DeadAirDivider = ({ gapMs }: { gapMs: number }) => (
  <div className="flex items-center gap-2 py-1.5" aria-label={`${formatMs(gapMs)} of silence`}>
    <div className="flex-1 border-t border-dashed border-border" />
    <span className="flex items-center gap-1 font-mono text-[10px] tabular-nums text-muted-foreground">
      <Timer size={10} />
      {formatMs(gapMs)} silence
    </span>
    <div className="flex-1 border-t border-dashed border-border" />
  </div>
)

export type TranscriptAlignment = 'chat' | 'left'

const TurnCard = ({ turn, highlighted, turnRef, alignment = 'chat', searchTerms = [] }: { turn: TurnRecord; highlighted?: boolean; turnRef?: React.Ref<HTMLDivElement>; alignment?: TranscriptAlignment; searchTerms?: string[] }) => {
  const isAgentFirst = turn.agent_first
  const isChat = alignment === 'chat'

  return (
    <div
      ref={turnRef}
      className={`group relative flex gap-3 transition-colors duration-500 rounded-lg ${highlighted ? 'bg-primary/5 ring-1 ring-primary/20' : ''}`}
    >
      {/* Timeline connector */}
      <div className="flex flex-col items-center pt-1">
        <div className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full border bg-card text-xs text-muted-foreground">
          {turn.turn_number}
        </div>
        <div className="w-px flex-1 bg-border" />
      </div>

      {/* Content */}
      <div className="flex-1 pb-8 min-w-0">
        {/* Turn badges row — only flags that aren't otherwise visible in the
            layout below. Tool-call count was removed because each tool call
            renders its own detailed card under the assistant message; the
            badge at the top made it look like the user had called a tool. */}
        <div className="flex items-center gap-1.5 mb-2 flex-wrap">
          {turn.interrupted && (
            <Badge variant="destructive" className="text-[10px] px-1.5 py-0">
              <Zap size={10} className="mr-0.5" />
              Interrupted
            </Badge>
          )}
          {isAgentFirst && (
            <Badge variant="outline" className="text-[10px] px-1.5 py-0">
              <Bot size={10} className="mr-0.5" />
              Agent initiated
            </Badge>
          )}
        </div>

        {/* Messages */}
        <div className="flex flex-col gap-2">
          {turn.user_text && (
            <div className="flex flex-col gap-1 max-w-[85%]">
              <div className="flex items-start gap-2">
                <div className="flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-bubble-user border border-border mt-0.5">
                  <User size={11} className="text-muted-foreground" />
                </div>
                <div className="rounded-lg rounded-tl-sm bg-bubble-user border border-border px-3 py-2">
                  <span className="text-xs"><HighlightedText text={turn.user_text} terms={searchTerms} /></span>
                </div>
              </div>
              {turn.user_transcript_confidence != null && (
                <div className="ml-7">
                  <ConfidencePill value={turn.user_transcript_confidence} />
                </div>
              )}
            </div>
          )}
          {/* Tool calls — rendered BEFORE the agent message so the visual
              order matches the causal order: user asked → agent called tool
              → agent replied with the result. */}
          {turn.tool_calls?.map((tc, i) => (
            <Collapsible
              key={i}
              className={`rounded-lg border bg-muted/30 overflow-hidden w-fit max-w-[85%] ${isChat ? 'self-end mr-7' : ''}`}
            >
              <CollapsibleTrigger className="group flex w-full items-center gap-2 px-3 py-2 bg-muted/50 cursor-pointer hover:bg-muted/70 data-[state=open]:border-b">
                <ChevronRight size={12} className="text-muted-foreground shrink-0 transition-transform group-data-[state=open]:rotate-90" />
                <Code2 size={12} className="text-primary shrink-0" />
                <span className="text-xs font-semibold text-primary">{tc.name}</span>
                {tc.is_error && (
                  <span className="text-[10px] text-foreground font-semibold uppercase tracking-wider">
                    failed
                  </span>
                )}
              </CollapsibleTrigger>
              <CollapsibleContent className="overflow-hidden data-[state=open]:animate-collapsible-down data-[state=closed]:animate-collapsible-up">
                <div className="px-3 py-2 space-y-1.5">
                  <div>
                    <span className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider">
                      Arguments
                    </span>
                    <div className="mt-1 text-xs font-mono space-y-0.5">
                      {Object.entries(tc.arguments).map(([key, val]) => (
                        <div key={key} className="flex gap-2">
                          <span className="text-muted-foreground shrink-0">{key}:</span>
                          <span className="text-foreground">{typeof val === 'string' ? val : JSON.stringify(val)}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                  {tc.output != null && (
                    <div>
                      <span className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider">
                        Output
                      </span>
                      <pre className={`mt-1 text-xs font-mono whitespace-pre-wrap break-all ${tc.is_error ? 'text-foreground font-semibold' : 'text-foreground'}`}>
                        {formatToolValue(tc.output)}
                      </pre>
                    </div>
                  )}
                </div>
              </CollapsibleContent>
            </Collapsible>
          ))}

          {turn.agent_text && (
            <div className={`flex items-start gap-2 max-w-[85%] ${isChat ? 'self-end flex-row-reverse' : ''}`}>
              <div className="flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-bubble-agent border border-info-border mt-0.5">
                <Bot size={11} className="text-info" />
              </div>
              <div className={`rounded-lg px-3 py-2 bg-bubble-agent border border-info-border ${isChat ? 'rounded-tr-sm' : 'rounded-tl-sm'}`}>
                <span className="text-xs"><HighlightedText text={turn.agent_text} terms={searchTerms} /></span>
              </div>
            </div>
          )}

          {/* Latency pills — agent response pipeline */}
          {(turn.user_perceived_ms != null || turn.stt_delay_ms != null || turn.llm_ttft_ms != null || turn.tts_ttfb_ms != null) && (
            <div className={`flex items-center gap-1 flex-wrap ${isChat ? 'justify-end mr-7' : ''}`}>
              <LatencyPill label="Perceived" ms={turn.user_perceived_ms} />
              <LatencyPill label="STT" ms={turn.stt_delay_ms} />
              <LatencyPill label="LLM TTFT" ms={turn.llm_ttft_ms} />
              <LatencyPill label="TTS" ms={turn.tts_ttfb_ms} />
            </div>
          )}
        </div>

        {/* Token stats for turn */}
        {((turn.llm_total_tokens ?? 0) > 0 || (turn.tts_characters ?? 0) > 0) && (
          <div className={`mt-1 flex items-center gap-3 text-[10px] text-muted-foreground ${isChat ? 'justify-end mr-7' : ''}`}>
            {turn.llm_prompt_tokens != null && <span>{turn.llm_prompt_tokens.toLocaleString()} prompt</span>}
            {turn.llm_completion_tokens != null && <span>{turn.llm_completion_tokens.toLocaleString()} completion</span>}
            {turn.tts_characters != null && turn.tts_characters > 0 && <span>{turn.tts_characters} TTS chars</span>}
          </div>
        )}
      </div>
    </div>
  )
}

const ChatMessageCard = ({ item, searchTerms = [] }: { item: ChatItem; searchTerms?: string[] }) => {
  const role = item.role ?? item.message?.role ?? 'unknown'
  const rawContent = item.content ?? item.message?.content ?? ''
  const content = Array.isArray(rawContent) ? rawContent.join(' ') : rawContent
  const isUser = role === 'user'

  return (
    <div className="flex gap-3 py-2">
      <div className={`flex h-5 w-5 shrink-0 items-center justify-center rounded-full mt-0.5 border ${
        isUser
          ? 'bg-bubble-user border-border'
          : 'bg-bubble-agent border-info-border'
      }`}>
        {isUser ? <User size={11} className="text-muted-foreground" /> : <Bot size={11} className="text-info" />}
      </div>
      <div>
        <span className="text-xxs-400 text-muted-foreground capitalize">{role}</span>
        <p className="text-xs leading-relaxed"><HighlightedText text={content} terms={searchTerms} /></p>
      </div>
    </div>
  )
}

export const TurnTranscriptSection = ({
  chatHistory: chatHistoryProp,
  metrics: metricsProp,
  highlightedTurn: highlightedTurnProp,
  embedded,
  alignment = 'chat',
  searchQuery,
}: {
  chatHistory?: ChatItem[] | null
  metrics?: SessionMetrics | null
  highlightedTurn?: number | null
  embedded?: boolean
  alignment?: TranscriptAlignment
  /** Active transcript-search query (?q=) — highlights matching words and
   * scrolls to the first matching turn. */
  searchQuery?: string
}) => {
  const hook = useTranscript()
  const chatHistory = chatHistoryProp ?? hook.chatHistory
  const metrics = metricsProp ?? hook.metrics
  const highlightedTurn = highlightedTurnProp ?? hook.highlightedTurn

  const turnRefs = useRef<Record<number, HTMLDivElement | null>>({})

  useEffect(() => {
    if (highlightedTurn == null) return
    const el = turnRefs.current[highlightedTurn]
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'nearest' })
    }
  }, [highlightedTurn])

  const searchTerms = useMemo(() => parseSearchTerms(searchQuery), [searchQuery])

  // Jump to the first matching turn when arriving from a search. An
  // explicit highlightedTurn deep-link wins; this only fills the gap.
  const turns = metrics?.turns
  useEffect(() => {
    if (!searchTerms.length || highlightedTurn != null) return
    const first = turns?.find((t) =>
      [t.user_text, t.agent_text].some((txt) => txt && textHasMatch(txt, searchTerms)),
    )
    if (first) {
      turnRefs.current[first.turn_number]?.scrollIntoView({ behavior: 'smooth', block: 'start' })
    }
  }, [searchTerms, highlightedTurn, turns])

  // If we have structured turn data from metrics, show that
  if (metrics?.turns?.length) {
    const deadAirThresholdMs = metrics.summary?.voice?.dead_air?.threshold_ms ?? 3000
    const content = (
      <>
        <div className="flex items-center gap-2 mb-5">
          <MessageSquare size={15} className="text-muted-foreground" />
          <span className="text-s-400 font-medium">Conversation</span>
          <span className="text-xs text-muted-foreground">
            {metrics.turns.length} turn{metrics.turns.length !== 1 ? 's' : ''}
          </span>
        </div>
        <div className="mx-auto max-w-3xl flex flex-col">
          {metrics.turns.map((turn, i) => (
            <Fragment key={turn.turn_id || i}>
              {turn.inter_turn_gap_ms != null && turn.inter_turn_gap_ms >= deadAirThresholdMs && (
                <DeadAirDivider gapMs={turn.inter_turn_gap_ms} />
              )}
              <TurnCard
                turn={turn}
                highlighted={highlightedTurn === turn.turn_number}
                turnRef={(el) => { turnRefs.current[turn.turn_number] = el }}
                alignment={alignment}
                searchTerms={searchTerms}
              />
            </Fragment>
          ))}
        </div>
      </>
    )

    if (embedded) return content
    return <div className="rounded-lg border bg-card p-5">{content}</div>
  }

  // Fallback to raw chat history
  if (chatHistory?.length) {
    const messages = chatHistory.filter((item) => item.type === 'message')
    return (
      <div className="space-y-3">
        <div className="flex items-center gap-2">
          <MessageSquare size={15} className="text-muted-foreground" />
          <span className="text-s-400 font-medium">Transcript</span>
          <span className="text-xs text-muted-foreground">({messages.length} messages)</span>
        </div>
        <div className="space-y-1 max-h-[600px] overflow-y-auto">
          {messages.map((item, i) => (
            <ChatMessageCard key={item.id || i} item={item} searchTerms={searchTerms} />
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className="flex items-center justify-center p-12 text-muted-foreground text-s-400">
      No turn data available
    </div>
  )
}
